import React, { useState } from 'react';

const App = () => {
  const [phone, setPhone] = useState('');
  const [code, setCode] = useState('');
  const [progress, setProgress] = useState(0);
  const [timer, setTimer] = useState(10);

  const handlePhoneChange = (e) => {
    setPhone(e.target.value);
  };

  const handleCodeChange = (e) => {
    setCode(e.target.value);
  };

  const handleTimer = () => {
    setTimer((prevTimer) => prevTimer - 1);
    if (prevTimer === 0) {
      setTimer(10);
    }
  };

  const handleProgress = () => {
    setProgress(Math.min(100, progress + 10));
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-[#C06C88] p-4 rounded-md">
        <h1 className="text-2xl text-[#B7D7CD]">Multi-Factor Enrollment</h1>
        <div className="flex flex-col items-center justify-center">
          <input
            type="tel"
            className="bg-[#B7D7CD] p-2 rounded-md text-[#411C56]"
            placeholder="+1 (123) 456-7890"
            value={phone}
            onChange={handlePhoneChange}
          />
          <button
            className="bg-[#B7D7CD] p-2 rounded-md text-[#411C56] hover:bg-[#C06C88]"
            onClick={handleCodeChange}
          >
            Verify via SMS
          </button>
        </div>
        <div className="flex flex-col items-center justify-center">
          <input
            type="tel"
            className="bg-[#B7D7CD] p-2 rounded-md text-[#411C56]"
            placeholder="123456"
            value={code}
            onChange={handleCodeChange}
          />
          <button
            className="bg-[#B7D7CD] p-2 rounded-md text-[#411C56] hover:bg-[#C06C88]"
            onClick={handleTimer}
          >
            Next Step
          </button>
        </div>
        <div className="flex flex-col items-center justify-center">
          <p className="text-[#411C56]">Time left: {timer}</p>
          <progress className="bg-[#C06C88]" value={progress} max={100} />
          <button
            className="bg-[#B7D7CD] p-2 rounded-md text-[#411C56] hover:bg-[#C06C88]"
            onClick={handleProgress}
          >
            Submit
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
